class StockSpanner {
    private java.util.List<Integer> prices = new java.util.ArrayList<>();

    public int next(int price) {
        prices.add(price);
        int span = 0;
        for (int i = prices.size() - 1; i >= 0; i--) {
            if (prices.get(i) <= price) {
                span++;
            } else {
                break;
            }
        }
        return span;
    }
}

class StockSpanner {
    private java.util.Deque<int[]> stack = new java.util.ArrayDeque<>(); // {price, span}

    public int next(int price) {
        int span = 1;
        while (!stack.isEmpty() && stack.peek()[0] <= price) {
            span += stack.pop()[1];
        }
        stack.push(new int[]{price, span});
        return span;
    }
}

class Solution {
    public int largestRectangleArea(int[] heights) {
        int maxArea = 0;
        for (int i = 0; i < heights.length; i++) {
            int minHeight = heights[i];
            for (int j = i; j < heights.length; j++) {
                minHeight = Math.min(minHeight, heights[j]);
                maxArea = Math.max(maxArea, minHeight * (j - i + 1));
            }
        }
        return maxArea;
    }
}

class Solution {
    public int largestRectangleArea(int[] heights) {
        java.util.Deque<Integer> stack = new java.util.ArrayDeque<>();
        int maxArea = 0;
        int n = heights.length;

        for (int i = 0; i <= n; i++) {
            int currentHeight = (i == n) ? 0 : heights[i];
            while (!stack.isEmpty() && heights[stack.peek()] >= currentHeight) {
                int height = heights[stack.pop()];
                int width = stack.isEmpty() ? i : i - stack.peek() - 1;
                maxArea = Math.max(maxArea, height * width);
            }
            stack.push(i);
        }
        return maxArea;
    }
}

class Solution {
    public int trap(int[] height) {
        int total = 0;
        for (int i = 0; i < height.length; i++) {
            int maxLeft = 0;
            for (int j = 0; j <= i; j++) maxLeft = Math.max(maxLeft, height[j]);
            int maxRight = 0;
            for (int j = i; j < height.length; j++) maxRight = Math.max(maxRight, height[j]);
            total += Math.min(maxLeft, maxRight) - height[i];
        }
        return total;
    }
}

class Solution {
    public int trap(int[] height) {
        java.util.Deque<Integer> stack = new java.util.ArrayDeque<>();
        int total = 0;

        for (int i = 0; i < height.length; i++) {
            while (!stack.isEmpty() && height[stack.peek()] < height[i]) {
                int bottom = stack.pop();
                if (stack.isEmpty()) break;
                int left = stack.peek();
                int width = i - left - 1;
                int boundedHeight = Math.min(height[left], height[i]) - height[bottom];
                total += width * boundedHeight;
            }
            stack.push(i);
        }
        return total;
    }
}

